import tkinter as tk
import base64
from io import BytesIO
from PIL import Image, ImageTk
from tkinter import messagebox
import subprocess
import re

IMAGE_PROJECTORS = """""".strip()
IMAGE_CONFIDENCE = """""".strip()

class MonitorHealthCheckApp:
    def __init__(self, root):
        self.root = root
        self.root.title("Evangel Projector & Monitor Health Check")
        self.root.geometry("450x200")

        # Button to check projectors and monitors
        self.button1 = tk.Button(
            self.root,
            text="Check Projectors",
            command=self.check_projectors_and_monitors,
            font=("Arial", 12)
        )
        self.button1.pack(pady=20)

        # Button to check thunderbolt and blackmagic
        self.button2 = tk.Button(
            self.root,
            text="Check Confidence Monitors",
            command=self.check_thunderbolt_and_blackmagic,
            font=("Arial", 12)
        )
        self.button2.pack(pady=0)

        def quit_app():
            root.destroy()   # Clean macOS-friendly shutdown

        quit_button = tk.Button(
            root,
            text="Quit",
            command=quit_app,
            font=("Arial", 12)  # Apply same font as Check Confidence Monitors button
        )
        quit_button.pack(padx=20, pady=20)

        # Footer text
        self.footer = tk.Label(
            self.root,
            text="Version 1.0 - Written by Alex Vanderveen",
            font=("Arial", 8)
        )
        self.footer.pack(side="bottom", pady=5)

    def run_command(self, command):
        try:
            result = subprocess.check_output(command, shell=True, stderr=subprocess.STDOUT, text=True)
            return result
        except subprocess.CalledProcessError as e:
            return e.output

    def check_projectors(self):
        #with open("monitorOFF", "r") as file:
            #output = file.read()
        output = self.run_command("ioreg -p IOUSB -lw0")
        projectors = re.findall(r"USB-C VGA Multiport Adapter", output)
        return len(projectors) > 0

    def check_monitors(self):
        #with open("monitorOFF", "r") as file:
            #output = file.read()
        output = self.run_command("system_profiler SPDisplaysDataType")
        monitors = re.findall(r"Super Video Graphics Array", output)
        return len(monitors) > 0

    def check_thunderbolt_enclosure(self):
        #with open("tb-bm-TRUE", "r") as file:
            #output = file.read()
        output = self.run_command("ioreg -p IOUSB -lw0")
        return "Device Name: TB31PCIEX16" in output

    def check_blackmagic_sdi(self):
        #with open("tb-bm-TRUE", "r") as file:
            #output = file.read()
        output = self.run_command("systemextensionsctl list")
        pattern1 = r"com\.blackmagic-design\.BlackmagicIO\.DExt.*\[activated enabled\]"
        pattern2 = r"com\.blackmagic-design\.desktopvideo\.Network\.DExt.*\[activated enabled\]"
        return bool(re.search(pattern1, output)) and bool(re.search(pattern2, output))
    
    def check_projectors_and_monitors(self):
        projectors = self.check_projectors()
        monitors = self.check_monitors()

        result = (
            f"Projectors plugged in: {projectors}<br>"
            f"Monitors plugged in: {monitors}"
        )

        if not projectors:
            messagebox.showwarning("Projectors Check", "No projectors detected.\n\nPlease check the USB-C to VGA adapter.")

        if projectors and not monitors:
            # Create a new window to display the results
            html_window = tk.Toplevel(self.root)
            html_window.title("Projectors Check")
            html_window.geometry("750x600")

            # Create a frame to hold the labels
            frame = tk.Frame(html_window)
            frame.pack(padx=10, pady=10)

            # Display monitor status
            self.display_status(frame, "Projectors USB adapter is plugged in ✅\n\nBut monitors aren't configured in the 'Screen Mirroring' widget 🧑‍💻\n\nIf the screen mirroring widget isn't working, ensure the VGA cable is securely connected\nto the USB-C adapter, or reboot the Mac 🔌", monitors)

            # Display image
            image_data = base64.b64decode(IMAGE_PROJECTORS, validate=False)
            image = Image.open(BytesIO(image_data))
            image_tk = ImageTk.PhotoImage(image)
            image_label = tk.Label(html_window, image=image_tk)
            image_label.image = image_tk  # Keep a reference to avoid garbage collection
            image_label.pack(pady=10)

            # Add OK button to close the window
            ok_button = tk.Button(
                html_window,
                text="OK",
                command=html_window.destroy,
                font=("Arial", 12)  
            )
            ok_button.pack(pady=10)
        
        if projectors and monitors:
            messagebox.showinfo("Projectors Check", "Projectors and monitors are plugged in and configured correctly ✅\n\nYou should see the display on the projectors 😇")

    def display_status(self, frame, message, status):
        label = tk.Label(
            frame,
            text=message.format(status=status),
            fg='black',
            font=("Arial", 12)
        )
        label.pack(anchor='w')

    def check_thunderbolt_and_blackmagic(self):
        thunderbolt = self.check_thunderbolt_enclosure()
        blackmagic = self.check_blackmagic_sdi()
        result = (
            f"Thunderbolt enclosure plugged in: {thunderbolt}<br>"
            f"BlackMagic SDI detected: {blackmagic}"
        )

        if not thunderbolt:
            messagebox.showwarning("Confidence Monitors Check", "External Thunderbolt enclosure not detected ❌\n\nPlease check the black StarTech box is plugged in and powered on 🔌")

        if thunderbolt and not blackmagic:
            messagebox.showwarning("Confidence Monitors Check", "StarTech Thunderbolt enclosure is plugged in and powered on ✅\nBlackMagic SDI card inside isn't detected ❌\n\nPlease check the Thunderbolt cable is securely connected to the Mac and the StarTech enclosure 🔌\n\nTry to powercycle the StarTech enclosure 🔌")

        if thunderbolt and blackmagic:
            # Create a new window to display the results
            html_window = tk.Toplevel(self.root)
            html_window.title("Confidence Monitors Check")
            html_window.geometry("750x890")

            # Create a frame to hold the labels
            frame = tk.Frame(html_window)
            frame.pack(padx=10, pady=10)

            # Display monitor status
            self.display_status(frame, "Thunderbolt enclosure plugged in ✅\nBlackMagic SDI enabled ✅\n\nConfirm settings in ProPresenter:\nPro Presenter > Screens > Configure Screens... >\nStage Screen 1 > Select DeckLink Duo (2) > Select 1080i60 🧑‍💻\n\nIf the issue persists, try another resolution, and verify the SDI cables\non the enclosure are secure on both ends 🤔", blackmagic)

            # Display image
            image_data = base64.b64decode(IMAGE_CONFIDENCE, validate=False)
            image = Image.open(BytesIO(image_data))
            image_tk = ImageTk.PhotoImage(image)
            image_label = tk.Label(html_window, image=image_tk)
            image_label.image = image_tk  # Keep a reference to avoid garbage collection
            image_label.pack(pady=10)

            # Add OK button to close the window
            ok_button = tk.Button(
                html_window,
                text="OK",
                command=html_window.destroy,
                font=("Arial", 12)
            )
            ok_button.pack(pady=10)

# GUI Setup
root = tk.Tk()
app = MonitorHealthCheckApp(root)
root.mainloop()